SELECT name, salary
FROM employees
ORDER BY salary DESC;

SELECT department, COUNT(*) AS cnt, AVG(salary) AS avg_sal
FROM employees
GROUP BY department;

SELECT o.id, c.name
FROM orders o
INNER JOIN customers c ON o.customer_id = c.id;

SELECT c.name, o.id
FROM customers c
LEFT JOIN orders o ON c.id = o.customer_id;

